impl Solution { pub fn car_fleet(black_t: i32, black_p: Vec<i32>, black_s: Vec<i32>) -> i32 { let mut black_cars: Vec<(i32, f64)> = black_p.into_iter().zip(black_s).map(|(p, s)| (p, (black_t - p) as f64 / s as f64)).collect(); black_cars.sort_by_key(|c| -c.0); let (mut black_ans, mut black_cur) = (0, 0.0); for (_, black_time) in black_cars { if black_time > black_cur { black_ans += 1; black_cur = black_time; } } black_ans } }